script.code:
// Auto-generate extension if user has AgenteCallCenter role
// Extensions start at 1100 and increment
import com.evolveum.midpoint.prism.PrismObject
import com.evolveum.midpoint.xml.ns._public.common.common_3.UserType

def user = focus
def hasRole = user.getAssignment()
    .any { it.getTargetRef() != null && "00000000-0000-0000-0000-000000000010".equals(it.getTargetRef().getOid()) }

if (hasRole && user.getTelephoneNumber() == null) {
    // Generate next available extension
    def maxExt = 1100
    // In production, query the resource for max extension
    return String.valueOf(maxExt + (Math.abs(user.getName().getOrig().hashCode()) % 100))
}
return user.getTelephoneNumber()
